import pytest, json, hashlib, boto3
from unittest.mock import patch, MagicMock
from your_module import EvidenceRecord, collect_encryption_config

def make_mock_config_response() -> dict:
    return {
        "EvaluationResults": [
            {"ComplianceType": "COMPLIANT",
             "EvaluationResultIdentifier": {
                 "EvaluationResultQualifier": {
                     "ConfigRuleName": "genai-s3-encryption-at-rest",
                     "ResourceId": "my-bucket",
                 }
             }}
        ]
    }

@patch("your_module.boto3.client")
def test_evidence_record_hash_stable(mock_client):
    mock_cfg = MagicMock()
    mock_cfg.get_compliance_details_by_config_rule.return_value = make_mock_config_response()
    mock_kms = MagicMock()
    mock_kms.sign.return_value = {"Signature": b"fake-sig"}
    mock_client.side_effect = lambda svc: mock_cfg if svc == "config" else mock_kms

    rec = collect_encryption_config("CC6.7-encryption-config")
    payload_bytes = json.dumps(rec.payload, sort_keys=True).encode()
    assert rec.content_hash == hashlib.sha256(payload_bytes).hexdigest()

def test_tampered_payload_detected():
    original  = json.dumps({"ComplianceType": "COMPLIANT"}, sort_keys=True).encode()
    tampered  = json.dumps({"ComplianceType": "NON_COMPLIANT"}, sort_keys=True).encode()
    orig_hash = hashlib.sha256(original).hexdigest()
    tamp_hash = hashlib.sha256(tampered).hexdigest()
    assert orig_hash != tamp_hash, "Hash must change when payload is modified"
